     1→/**
     2→ * MMS Man-hour Leveling Service Unit Tests
     3→ *
     4→ * Tests for the Man-hour Leveling Service covering:
     5→ * - Service initialization and singleton pattern
     6→ * - Type definitions and interfaces
     7→ * - Leveling strategy configurations
     8→ * - Utilization targets and thresholds
     9→ * - Imbalance detection logic
    10→ * - Adjustment generation algorithms
    11→ * - Metrics calculation
    12→ *
    13→ * Note: These tests use Bun's test framework and document expected behavior.
    14→ * Integration tests with actual database should be in a separate test suite.
    15→ *
    16→ * @see src/services/man-hour-leveling.ts
    17→ * @see specs/004-domain-services.md Section 4.6
    18→ */
    19→
    20→import { describe, test, expect } from 'bun:test';
    21→import {
    22→  ManHourLevelingService,
    23→  getManHourLevelingService,
    24→  LEVELING_STRATEGIES,
    25→  type AdjustmentType,
    26→  type RiskLevel,
    27→  type AdjustmentStatus,
    28→  type LevelingStrategy,
    29→  type LevelingTimePeriod,
    30→  type RequiredHours,
    31→  type AvailableHours,
    32→  type ProjectionData,
    33→  type ProposedAdjustment,
    34→  type LevelingMetrics,
    35→  type LevelingImprovement,
    36→  type LevelingResult,
    37→  type GenerateProjectionsRequest,
    38→  type UpdateCapacityRequest,
    39→  type ProjectionFilters,
    40→  type AdjustmentFilters,
    41→} from './man-hour-leveling';
    42→
    43→describe('ManHourLevelingService', () => {
    44→  describe('Initialization', () => {
    45→    test('should create a ManHourLevelingService instance', () => {
    46→      const service = new ManHourLevelingService();
    47→      expect(service).toBeDefined();
    48→      expect(service).toBeInstanceOf(ManHourLevelingService);
    49→    });
    50→
    51→    test('should return singleton instance via getManHourLevelingService', () => {
    52→      const instance1 = getManHourLevelingService();
    53→      const instance2 = getManHourLevelingService();
    54→      expect(instance1).toBe(instance2);
    55→    });
    56→  });
    57→
    58→  describe('Leveling Strategies', () => {
    59→    test('should have 5 strategies in priority order', () => {
    60→      expect(LEVELING_STRATEGIES).toHaveLength(5);
    61→    });
    62→
    63→    test('should have ADVANCE_PM as priority 1', () => {
    64→      const advancePm = LEVELING_STRATEGIES.find((s) => s.type === 'ADVANCE_PM');
    65→      expect(advancePm).toBeDefined();
    66→      expect(advancePm?.priority).toBe(1);
    67→      expect(advancePm?.costMultiplier).toBe(1.1);
    68→      expect(advancePm?.riskLevel).toBe('LOW');
    69→      expect(advancePm?.maxHoursPerWeek).toBe(40);
    70→    });
    71→
    72→    test('should have DEFER_PM as priority 2', () => {
    73→      const deferPm = LEVELING_STRATEGIES.find((s) => s.type === 'DEFER_PM');
    74→      expect(deferPm).toBeDefined();
    75→      expect(deferPm?.priority).toBe(2);
    76→      expect(deferPm?.costMultiplier).toBe(1.05);
    77→      expect(deferPm?.riskLevel).toBe('LOW');
    78→      expect(deferPm?.maxHoursPerWeek).toBe(40);
    79→    });
    80→
    81→    test('should have ADD_OVERTIME as priority 3', () => {
    82→      const overtime = LEVELING_STRATEGIES.find((s) => s.type === 'ADD_OVERTIME');
    83→      expect(overtime).toBeDefined();
    84→      expect(overtime?.priority).toBe(3);
    85→      expect(overtime?.costMultiplier).toBe(1.5);
    86→      expect(overtime?.riskLevel).toBe('NONE');
    87→      expect(overtime?.maxHoursPerWeek).toBe(80);
    88→    });
    89→
    90→    test('should have CROSS_DEPOT as priority 4', () => {
    91→      const crossDepot = LEVELING_STRATEGIES.find((s) => s.type === 'CROSS_DEPOT');
    92→      expect(crossDepot).toBeDefined();
    93→      expect(crossDepot?.priority).toBe(4);
    94→      expect(crossDepot?.costMultiplier).toBe(1.3);
    95→      expect(crossDepot?.riskLevel).toBe('MEDIUM');
    96→      expect(crossDepot?.maxHoursPerWeek).toBe(60);
    97→    });
    98→
    99→    test('should have ADD_CONTRACTOR as priority 5', () => {
   100→      const contractor = LEVELING_STRATEGIES.find((s) => s.type === 'ADD_CONTRACTOR');
   101→      expect(contractor).toBeDefined();
   102→      expect(contractor?.priority).toBe(5);
   103→      expect(contractor?.costMultiplier).toBe(2.0);
   104→      expect(contractor?.riskLevel).toBe('MEDIUM');
   105→      expect(contractor?.maxHoursPerWeek).toBe(100);
   106→    });
   107→
   108→    test('should be sorted by priority ascending', () => {
   109→      for (let i = 1; i < LEVELING_STRATEGIES.length; i++) {
   110→        expect(LEVELING_STRATEGIES[i].priority).toBeGreaterThan(
   111→          LEVELING_STRATEGIES[i - 1].priority
   112→        );
   113→      }
   114→    });
   115→
   116→    test('should match spec 004.6 strategy definitions', () => {
   117→      // From spec: Priority order with cost multipliers and risk levels
   118→      const expected: Array<{ type: AdjustmentType; costMultiplier: number; riskLevel: RiskLevel }> = [
   119→        { type: 'ADVANCE_PM', costMultiplier: 1.1, riskLevel: 'LOW' },
   120→        { type: 'DEFER_PM', costMultiplier: 1.05, riskLevel: 'LOW' },
   121→        { type: 'ADD_OVERTIME', costMultiplier: 1.5, riskLevel: 'NONE' },
   122→        { type: 'CROSS_DEPOT', costMultiplier: 1.3, riskLevel: 'MEDIUM' },
   123→        { type: 'ADD_CONTRACTOR', costMultiplier: 2.0, riskLevel: 'MEDIUM' },
   124→      ];
   125→
   126→      for (const exp of expected) {
   127→        const strategy = LEVELING_STRATEGIES.find((s) => s.type === exp.type);
   128→        expect(strategy).toBeDefined();
   129→        expect(strategy?.costMultiplier).toBe(exp.costMultiplier);
   130→        expect(strategy?.riskLevel).toBe(exp.riskLevel);
   131→      }
   132→    });
   133→  });
   134→
   135→  describe('Type Definitions', () => {
