   324→  /**
   325→   * Generate projections and leveling recommendations
   326→   *
   327→   * This is the main entry point for the leveling engine.
   328→   * It calculates raw projections, identifies imbalances, generates adjustments,
   329→   * and persists the results.
   330→   */
   331→  async generateProjections(request: GenerateProjectionsRequest = {}): Promise<LevelingResult> {
   332→    const horizonWeeks = request.horizonWeeks ?? 12;
   333→    const granularity = request.granularity ?? 'WEEKLY';
   334→
   335→    return this.traced(
   336→      'generateProjections',
   337→      async (span) => {
   338→        span.setAttribute('mms.manhour.horizon_weeks', horizonWeeks);
   339→        span.setAttribute('mms.manhour.granularity', granularity);
   340→
   341→        const runId = crypto.randomUUID();
   342→        span.setAttribute('mms.manhour.run_id', runId);
   343→
   344→        // 1. Get depots to process
   345→        const depotIds = await this.resolveDepotIds(request.depotIds);
   346→        if (depotIds.length === 0) {
   347→          throw new ValidationError('No depots found for projection');
   348→        }
   349→        span.setAttribute('mms.manhour.depot_count', depotIds.length);
   350→
   351→        // 2. Calculate raw projections
   352→        const rawProjections = await this.calculateRawProjections(
   353→          depotIds,
   354→          horizonWeeks,
   355→          granularity
   356→        );
   357→
   358→        // 3. Identify imbalances
   359→        const imbalances = this.identifyImbalances(rawProjections);
   360→        span.setAttribute('overloadedWeeks', imbalances.overloaded.length);
   361→        span.setAttribute('underutilizedWeeks', imbalances.underutilized.length);
   362→
   363→        // 4. Generate adjustments using multiple strategies
   364→        const adjustments = await this.generateAdjustments(rawProjections);
   365→        span.setAttribute('adjustmentCount', adjustments.length);
   366→
   367→        // 5. Apply adjustments to get leveled projections
   368→        const leveledProjections = this.applyAdjustments(rawProjections, adjustments);
   369→
   370→        // 6. Calculate metrics
   371→        const originalMetrics = this.calculateMetrics(rawProjections);
   372→        const leveledMetrics = this.calculateMetrics(leveledProjections);
   373→
   374→        // 7. Persist projections and adjustments
   375→        await this.persistProjections(runId, rawProjections, adjustments);
   376→
   377→        // 8. Build result
   378→        const improvement: LevelingImprovement = {
   379→          utilizationDelta: leveledMetrics.avgUtilization - originalMetrics.avgUtilization,
   380→          overloadedWeeksReduced: originalMetrics.overloadedWeeks - leveledMetrics.overloadedWeeks,
   381→          underutilizedWeeksReduced:
   382→            originalMetrics.underutilizedWeeks - leveledMetrics.underutilizedWeeks,
   383→          totalCostImpact: adjustments.reduce((sum, a) => sum + a.costImpact, 0),
   384→        };
   385→
   386→        this.log.info(
   387→          {
   388→            runId,
   389→            horizonWeeks,
   390→            depotCount: depotIds.length,
   391→            adjustmentCount: adjustments.length,
   392→            improvement,
   393→          },
   394→          'Generated man-hour projections'
   395→        );
   396→
   397→        return {
   398→          projectionRunId: runId,
   399→          generatedAt: new Date(),
   400→          horizonWeeks,
   401→          depotIds,
   402→          original: { projections: rawProjections, metrics: originalMetrics },
   403→          leveled: { projections: leveledProjections, metrics: leveledMetrics },
   404→          adjustments,
   405→          improvement,
   406→        };
   407→      },
   408→      { 'mms.manhour.requested_depots': request.depotIds?.length ?? 0 }
   409→    );
   410→  }
