   687→  private async resolveDepotIds(requestedIds?: string[]): Promise<string[]> {
   688→    if (requestedIds && requestedIds.length > 0) {
   689→      return requestedIds;
   690→    }
   691→
   692→    // Get all active depots
   693→    const allDepots = await this.db.query.depots.findMany({
   694→      columns: { id: true },
   695→    });
   696→
   697→    return allDepots.map((d) => d.id);
   698→  }
