   700→  /**
   701→   * Calculate raw man-hour projections from PM schedule
   702→   */
   703→  private async calculateRawProjections(
   704→    depotIds: string[],
   705→    horizonWeeks: number,
   706→    granularity: 'WEEKLY' | 'MONTHLY'
   707→  ): Promise<ProjectionData[]> {
   708→    const projections: ProjectionData[] = [];
   709→    const now = new Date();
   710→    const startDate = startOfWeek(now, { weekStartsOn: 1 }); // Monday
   711→
   712→    // Get depot info
   713→    const depotList = await this.db.query.depots.findMany({
   714→      where: inArray(depots.id, depotIds),
   715→    });
   716→    const depotMap = new Map(depotList.map((d) => [d.id, d]));
   717→
   718→    for (const depotId of depotIds) {
   719→      const depot = depotMap.get(depotId);
   720→      if (!depot) continue;
   721→
   722→      // Get capacity for depot
   723→      const capacity = await this.getCapacity(depotId);
   724→      const weeklyCapacity = this.calculateWeeklyCapacity(capacity);
   725→
   726→      for (let weekOffset = 0; weekOffset < horizonWeeks; weekOffset++) {
   727→        const weekStart = addWeeks(startDate, weekOffset);
   728→        const weekEnd = endOfWeek(weekStart, { weekStartsOn: 1 });
   729→
   730→        // Get PM hours for this week
   731→        const pmHours = await this.getPmHoursForPeriod(depotId, weekStart, weekEnd);
   732→
   733→        // Calculate available hours
   734→        const regularHours = weeklyCapacity.regular;
   735→        const overtimeMax =
   736→          regularHours * (capacity ? parseFloat(capacity.maxOvertimePct ?? '20') / 100 : 0.2);
   737→
   738→        const required: RequiredHours = {
   739→          pm: pmHours,
   740→          corrective: 0, // TODO: Integrate with unavailability events
   741→          overhaul: 0, // TODO: Separate overhaul tracking
   742→          total: pmHours,
   743→        };
   744→
   745→        const available: AvailableHours = {
   746→          regular: regularHours,
   747→          overtime: overtimeMax,
   748→          total: regularHours + overtimeMax,
   749→        };
   750→
   751→        const variance = available.total - required.total;
   752→        const utilizationPct = available.total > 0 ? required.total / available.total : 0;
   753→
   754→        projections.push({
   755→          depotId,
   756→          depotCode: depot.code,
   757→          week: weekStart,
   758→          granularity,
   759→          required,
   760→          available,
   761→          variance,
   762→          utilizationPct,
   763→          isOverloaded: utilizationPct > MAX_UTILIZATION,
   764→          isUnderutilized: utilizationPct < MIN_UTILIZATION,
   765→        });
   766→      }
   767→    }
   768→
   769→    return projections;
   770→  }
   771→
   772→  /**
   773→   * Calculate weekly capacity from configuration
   774→   */
   775→  private calculateWeeklyCapacity(
   776→    capacity: ManhourCapacity | null
   777→  ): { regular: number; overtime: number } {
   778→    if (!capacity) {
   779→      // Default capacity when not configured
   780→      return { regular: 200, overtime: 40 };
   781→    }
   782→
   783→    const dayHours = parseFloat(capacity.dayShiftHours ?? '0');
   784→    const nightHours = parseFloat(capacity.nightShiftHours ?? '0');
   785→    const weekendHours = parseFloat(capacity.weekendHours ?? '0');
   786→    const maxOvertimePct = parseFloat(capacity.maxOvertimePct ?? '20') / 100;
   787→
   788→    const regular = dayHours * 5 + nightHours * 5 + weekendHours * 2;
   789→    const overtime = regular * maxOvertimePct;
   790→
   791→    return { regular, overtime };
   792→  }
   793→
   794→  /**
   795→   * Get total PM hours for a time period
   796→   */
   797→  private async getPmHoursForPeriod(
   798→    depotId: string,
   799→    startDate: Date,
   800→    endDate: Date
   801→  ): Promise<number> {
   802→    const startStr = format(startDate, 'yyyy-MM-dd');
   803→    const endStr = format(endDate, 'yyyy-MM-dd');
   804→
   805→    // Get scheduled PMs for the period
   806→    const scheduledPMs = await this.db
   807→      .select({
   808→        pmTypeId: pmSchedule.pmTypeId,
   809→        count: count(),
   810→      })
   811→      .from(pmSchedule)
   812→      .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
   813→      .where(
   814→        and(
   815→          eq(trains.currentDepotId, depotId),
   816→          gte(pmSchedule.targetDate, startStr),
   817→          lte(pmSchedule.targetDate, endStr),
   818→          eq(pmSchedule.status, 'SCHEDULED'),
   819→          isNull(pmSchedule.scenarioId) // Only real schedule, not scenarios
   820→        )
   821→      )
   822→      .groupBy(pmSchedule.pmTypeId);
   823→
   824→    if (scheduledPMs.length === 0) {
   825→      return 0;
   826→    }
   827→
   828→    // Get estimated hours for each PM type
   829→    const pmTypeIds = scheduledPMs.map((p) => p.pmTypeId);
   830→    const pmTypeHours = await this.db.query.pmTypes.findMany({
   831→      where: inArray(pmTypes.id, pmTypeIds),
   832→      columns: { id: true, estimatedHours: true },
   833→    });
   834→
   835→    const hoursMap = new Map(pmTypeHours.map((pt) => [pt.id, parseFloat(pt.estimatedHours ?? '0')]));
   836→
   837→    // Calculate total hours
   838→    let totalHours = 0;
   839→    for (const pm of scheduledPMs) {
   840→      const hours = hoursMap.get(pm.pmTypeId) ?? 0;
   841→      totalHours += hours * pm.count;
   842→    }
   843→
   844→    return totalHours;
   845→  }
