   864→  // ===========================================================================
   865→  // Private: Adjustment Generation
   866→  // ===========================================================================
   867→
   868→  /**
   869→   * Generate adjustments to level workload
   870→   */
   871→  private async generateAdjustments(
   872→    projections: ProjectionData[]
   873→  ): Promise<ProposedAdjustment[]> {
   874→    const adjustments: ProposedAdjustment[] = [];
   875→
   876→    // Group projections by depot
   877→    const byDepot = this.groupByDepot(projections);
   878→
   879→    for (const depotProjections of byDepot.values()) {
   880→      const overloaded = depotProjections.filter((p) => p.isOverloaded);
   881→      const underutilized = depotProjections.filter((p) => p.isUnderutilized);
   882→
   883→      // Track remaining capacity in underutilized weeks
   884→      const underutilizedCapacity = new Map(
   885→        underutilized.map((p) => [
   886→          p.week.toISOString(),
   887→          p.available.total - p.required.total,
   888→        ])
   889→      );
   890→
   891→      for (const overWeek of overloaded) {
   892→        let remainingExcess = overWeek.required.total - overWeek.available.total;
   893→
   894→        // Try each strategy in priority order
   895→        for (const strategy of LEVELING_STRATEGIES) {
   896→          if (remainingExcess <= 0) break;
   897→
   898→          const adjustment = await this.tryStrategy(
   899→            strategy,
   900→            overWeek,
   901→            underutilized,
   902→            underutilizedCapacity,
   903→            depotProjections,
   904→            remainingExcess
   905→          );
   906→
   907→          if (adjustment) {
   908→            adjustments.push(adjustment);
   909→            remainingExcess -= adjustment.hoursAdjusted;
   910→
   911→            // Update underutilized capacity if we used some
   912→            if (
   913→              adjustment.targetPeriod &&
   914→              (adjustment.type === 'ADVANCE_PM' || adjustment.type === 'DEFER_PM')
   915→            ) {
   916→              const key = adjustment.targetPeriod.start.toISOString();
   917→              const current = underutilizedCapacity.get(key) ?? 0;
   918→              underutilizedCapacity.set(key, current - adjustment.hoursAdjusted);
   919→            }
   920→          }
   921→        }
   922→
   923→        // If still overloaded, flag for manual review
   924→        if (remainingExcess > 0) {
   925→          adjustments.push({
   926→            type: 'MANUAL_REVIEW',
   927→            sourcePeriod: {
   928→              start: overWeek.week,
   929→              end: addDays(overWeek.week, 7),
   930→            },
   931→            hoursAdjusted: 0,
   932→            affectedPMs: [],
   933→            affectedTrains: [],
   934→            costImpact: 0,
   935→            riskLevel: 'HIGH',
   936→            reason: `Unable to resolve ${remainingExcess.toFixed(0)}h overload - requires manual intervention`,
   937→          });
   938→        }
   939→      }
   940→    }
   941→
   942→    return adjustments;
   943→  }
