   945→  /**
   946→   * Try a specific leveling strategy
   947→   */
   948→  private async tryStrategy(
   949→    strategy: LevelingStrategy,
   950→    overloadedWeek: ProjectionData,
   951→    underutilizedWeeks: ProjectionData[],
   952→    underutilizedCapacity: Map<string, number>,
   953→    allProjections: ProjectionData[],
   954→    excessHours: number
   955→  ): Promise<ProposedAdjustment | null> {
   956→    const maxHours = Math.min(strategy.maxHoursPerWeek, excessHours);
   957→    const baseRate = await this.getBaseRate(overloadedWeek.depotId);
   958→
   959→    switch (strategy.type) {
   960→      case 'ADVANCE_PM':
   961→      case 'DEFER_PM':
   962→        return this.tryShiftPmStrategy(
   963→          strategy,
   964→          overloadedWeek,
   965→          underutilizedWeeks,
   966→          underutilizedCapacity,
   967→          maxHours,
   968→          baseRate
   969→        );
   970→
   971→      case 'ADD_OVERTIME':
   972→        return this.tryOvertimeStrategy(strategy, overloadedWeek, maxHours, baseRate);
   973→
   974→      case 'CROSS_DEPOT':
   975→        return this.tryCrossDepotStrategy(strategy, overloadedWeek, maxHours, baseRate);
   976→
   977→      case 'ADD_CONTRACTOR':
   978→        return this.tryContractorStrategy(strategy, overloadedWeek, maxHours, baseRate);
   979→
   980→      default:
   981→        return null;
   982→    }
   983→  }
