   985→  /**
   986→   * Try ADVANCE_PM or DEFER_PM strategy
   987→   */
   988→  private async tryShiftPmStrategy(
   989→    strategy: LevelingStrategy,
   990→    overloadedWeek: ProjectionData,
   991→    underutilizedWeeks: ProjectionData[],
   992→    underutilizedCapacity: Map<string, number>,
   993→    maxHours: number,
   994→    baseRate: number
   995→  ): Promise<ProposedAdjustment | null> {
   996→    const direction = strategy.type === 'ADVANCE_PM' ? -1 : 1;
   997→
   998→    // Find candidate weeks (before for ADVANCE, after for DEFER)
   999→    const candidates = underutilizedWeeks
  1000→      .filter((w) => {
  1001→        const weekDiff = differenceInWeeks(w.week, overloadedWeek.week);
  1002→        const remainingCapacity = underutilizedCapacity.get(w.week.toISOString()) ?? 0;
  1003→        return (
  1004→          w.depotId === overloadedWeek.depotId &&
  1005→          weekDiff * direction > 0 &&
  1006→          Math.abs(weekDiff) <= 4 &&
  1007→          remainingCapacity > MIN_SHIFT_HOURS
  1008→        );
  1009→      })
  1010→      .sort(
  1011→        (a, b) =>
  1012→          Math.abs(differenceInWeeks(a.week, overloadedWeek.week)) -
  1013→          Math.abs(differenceInWeeks(b.week, overloadedWeek.week))
  1014→      );
  1015→
  1016→    for (const candidate of candidates) {
  1017→      const availableCapacity = underutilizedCapacity.get(candidate.week.toISOString()) ?? 0;
  1018→      const shiftHours = Math.min(maxHours, availableCapacity * 0.8);
  1019→
  1020→      if (shiftHours >= MIN_SHIFT_HOURS) {
  1021→        // Find PMs that can be shifted
  1022→        const shiftablePMs = await this.findShiftablePMs(
  1023→          overloadedWeek,
  1024→          candidate,
  1025→          shiftHours,
  1026→          strategy.type as 'ADVANCE_PM' | 'DEFER_PM'
  1027→        );
  1028→
  1029→        if (shiftablePMs.length > 0) {
  1030→          const actualHours = shiftablePMs.reduce((sum, pm) => sum + pm.estimatedHours, 0);
  1031→
  1032→          const weekNumSource = format(overloadedWeek.week, 'ww');
  1033→          const weekNumTarget = format(candidate.week, 'ww');
  1034→          const action = strategy.type === 'DEFER_PM' ? 'Defer' : 'Advance';
  1035→
  1036→          return {
  1037→            type: strategy.type,
  1038→            sourcePeriod: {
  1039→              start: overloadedWeek.week,
  1040→              end: addDays(overloadedWeek.week, 7),
  1041→            },
  1042→            targetPeriod: {
  1043→              start: candidate.week,
  1044→              end: addDays(candidate.week, 7),
  1045→            },
  1046→            hoursAdjusted: actualHours,
  1047→            affectedPMs: shiftablePMs.map((pm) => pm.id),
  1048→            affectedTrains: [...new Set(shiftablePMs.map((pm) => pm.trainId))],
  1049→            costImpact: actualHours * baseRate * (strategy.costMultiplier - 1),
  1050→            riskLevel: strategy.riskLevel,
  1051→            reason: `${action} ${actualHours.toFixed(0)}h (${shiftablePMs.length} PMs) from Week ${weekNumSource} to Week ${weekNumTarget}`,
  1052→          };
  1053→        }
  1054→      }
  1055→    }
  1056→
  1057→    return null;
  1058→  }
  1059→
  1060→  /**
  1061→   * Try ADD_OVERTIME strategy
  1062→   */
  1063→  private tryOvertimeStrategy(
  1064→    strategy: LevelingStrategy,
