  1168→  /**
  1169→   * Find PMs that can be shifted to another week
  1170→   */
  1171→  private async findShiftablePMs(
  1172→    fromWeek: ProjectionData,
  1173→    toWeek: ProjectionData,
  1174→    targetHours: number,
  1175→    strategy: 'ADVANCE_PM' | 'DEFER_PM'
  1176→  ): Promise<ShiftablePM[]> {
  1177→    const fromStart = format(fromWeek.week, 'yyyy-MM-dd');
  1178→    const fromEnd = format(addDays(fromWeek.week, 6), 'yyyy-MM-dd');
  1179→
  1180→    // Get PMs in the overloaded week
  1181→    const scheduledPMs = await this.db
  1182→      .select({
  1183→        id: pmSchedule.id,
  1184→        trainId: pmSchedule.trainId,
  1185→        pmTypeId: pmSchedule.pmTypeId,
  1186→        targetDate: pmSchedule.targetDate,
  1187→        constraintStart: pmSchedule.constraintStart,
  1188→        constraintEnd: pmSchedule.constraintEnd,
  1189→        isLocked: pmSchedule.isLocked,
  1190→      })
  1191→      .from(pmSchedule)
  1192→      .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
  1193→      .where(
  1194→        and(
  1195→          eq(trains.currentDepotId, fromWeek.depotId),
  1196→          gte(pmSchedule.targetDate, fromStart),
  1197→          lte(pmSchedule.targetDate, fromEnd),
  1198→          inArray(pmSchedule.status, ['SCHEDULED']), // Not CONFIRMED, IN_PROGRESS, or COMPLETED
  1199→          eq(pmSchedule.isLocked, false), // Not locked
  1200→          isNull(pmSchedule.scenarioId) // Real schedule
  1201→        )
  1202→      );
  1203→
  1204→    if (scheduledPMs.length === 0) {
  1205→      return [];
  1206→    }
  1207→
  1208→    // Get PM type info
  1209→    const pmTypeIds = [...new Set(scheduledPMs.map((p) => p.pmTypeId))];
  1210→    const pmTypeInfo = await this.db.query.pmTypes.findMany({
  1211→      where: inArray(pmTypes.id, pmTypeIds),
  1212→      columns: { id: true, pmCode: true, estimatedHours: true },
  1213→    });
  1214→    const typeMap = new Map(pmTypeInfo.map((pt) => [pt.id, pt]));
  1215→
  1216→    // Filter PMs that can be shifted to target week
  1217→    const shiftablePMs: ShiftablePM[] = [];
  1218→    let accumulatedHours = 0;
  1219→
  1220→    for (const pm of scheduledPMs) {
  1221→      if (accumulatedHours >= targetHours) break;
  1222→
  1223→      const pmType = typeMap.get(pm.pmTypeId);
  1224→      if (!pmType) continue;
  1225→
  1226→      const constraintStart = pm.constraintStart ? parseISO(pm.constraintStart) : null;
  1227→      const constraintEnd = pm.constraintEnd ? parseISO(pm.constraintEnd) : null;
  1228→
  1229→      // Check if target week is within compliance window
  1230→      const targetDate = strategy === 'ADVANCE_PM' ? toWeek.week : addDays(toWeek.week, 6);
  1231→
  1232→      const withinWindow =
  1233→        (!constraintStart || !isBefore(targetDate, constraintStart)) &&
  1234→        (!constraintEnd || !isAfter(targetDate, constraintEnd));
  1235→
  1236→      if (withinWindow) {
  1237→        const hours = parseFloat(pmType.estimatedHours ?? '0');
  1238→        shiftablePMs.push({
  1239→          id: pm.id,
  1240→          trainId: pm.trainId,
  1241→          pmTypeCode: pmType.pmCode,
  1242→          estimatedHours: hours,
  1243→          currentDate: parseISO(pm.targetDate),
  1244→          constraintStart: constraintStart ?? new Date(0),
  1245→          constraintEnd: constraintEnd ?? new Date(9999, 11, 31),
  1246→        });
  1247→        accumulatedHours += hours;
  1248→      }
  1249→    }
  1250→
  1251→    return shiftablePMs;
  1252→  }
