  1254→  /**
  1255→   * Find other depots with available capacity
  1256→   */
  1257→  private async findDepotsWithCapacity(
  1258→    week: Date,
  1259→    minHours: number,
  1260→    excludeDepotId: string
  1261→  ): Promise<DepotWithCapacity[]> {
  1262→    // Get all depots except the excluded one
  1263→    const otherDepots = await this.db.query.depots.findMany({
  1264→      where: sql`${depots.id} != ${excludeDepotId}`,
  1265→    });
  1266→
  1267→    const results: DepotWithCapacity[] = [];
  1268→
  1269→    for (const depot of otherDepots) {
  1270→      const capacity = await this.getCapacity(depot.id, week);
  1271→      if (!capacity) continue;
  1272→
  1273→      // Get PM hours for this depot/week
  1274→      const pmHours = await this.getPmHoursForPeriod(depot.id, week, addDays(week, 6));
  1275→
  1276→      // Calculate available capacity
  1277→      const weeklyCapacity = this.calculateWeeklyCapacity(capacity);
  1278→      const availableHours = weeklyCapacity.regular + weeklyCapacity.overtime - pmHours;
  1279→
  1280→      if (availableHours >= minHours) {
  1281→        results.push({
  1282→          depotId: depot.id,
  1283→          depotCode: depot.code,
  1284→          depotName: depot.name,
  1285→          availableHours: Math.min(availableHours, minHours),
  1286→        });
  1287→      }
  1288→    }
  1289→
  1290→    // Sort by available hours (descending)
  1291→    return results.sort((a, b) => b.availableHours - a.availableHours);
  1292→  }
