  1294→  /**
  1295→   * Get base labor rate for a depot
  1296→   */
  1297→  private async getBaseRate(depotId?: string): Promise<number> {
  1298→    if (!depotId) {
  1299→      return DEFAULT_BASE_RATE;
  1300→    }
  1301→
  1302→    const rate = await this.db.query.laborRates.findFirst({
  1303→      where: and(
  1304→        eq(laborRates.depotId, depotId),
  1305→        lte(laborRates.effectiveFrom, format(new Date(), 'yyyy-MM-dd')),
  1306→        or(isNull(laborRates.effectiveTo), gte(laborRates.effectiveTo, format(new Date(), 'yyyy-MM-dd')))
  1307→      ),
  1308→      orderBy: [desc(laborRates.effectiveFrom)],
  1309→    });
  1310→
  1311→    return rate ? parseFloat(rate.regularHourlyRate ?? String(DEFAULT_BASE_RATE)) : DEFAULT_BASE_RATE;
  1312→  }
