  1314→  // ===========================================================================
  1315→  // Private: Apply Adjustments & Calculate Metrics
  1316→  // ===========================================================================
  1317→
  1318→  /**
  1319→   * Apply adjustments to projections (simulation, not persisted)
  1320→   */
  1321→  private applyAdjustments(
  1322→    projections: ProjectionData[],
  1323→    adjustments: ProposedAdjustment[]
  1324→  ): ProjectionData[] {
  1325→    // Create deep copy
  1326→    const leveled = projections.map((p) => ({
  1327→      ...p,
  1328→      required: { ...p.required },
  1329→      available: { ...p.available },
  1330→    }));
  1331→
  1332→    // Build lookup by week
  1333→    const weekMap = new Map(leveled.map((p) => [p.week.toISOString(), p]));
  1334→
  1335→    for (const adj of adjustments) {
  1336→      if (adj.type === 'MANUAL_REVIEW') continue;
  1337→
  1338→      const sourceKey = adj.sourcePeriod.start.toISOString();
  1339→      const source = weekMap.get(sourceKey);
  1340→
  1341→      if (adj.type === 'ADVANCE_PM' || adj.type === 'DEFER_PM') {
  1342→        // Move hours from source to target
  1343→        if (source && adj.targetPeriod) {
  1344→          const targetKey = adj.targetPeriod.start.toISOString();
  1345→          const target = weekMap.get(targetKey);
  1346→
  1347→          if (target) {
  1348→            source.required.pm -= adj.hoursAdjusted;
  1349→            source.required.total -= adj.hoursAdjusted;
  1350→            target.required.pm += adj.hoursAdjusted;
  1351→            target.required.total += adj.hoursAdjusted;
  1352→          }
  1353→        }
  1354→      } else if (adj.type === 'ADD_OVERTIME') {
  1355→        // Increase available hours in source
  1356→        if (source) {
  1357→          // Overtime is already counted in available.total
  1358→          // No change needed to projected available hours
  1359→        }
  1360→      } else if (adj.type === 'CROSS_DEPOT' || adj.type === 'ADD_CONTRACTOR') {
  1361→        // Reduce required hours in source (work transferred out)
  1362→        if (source) {
  1363→          source.required.total -= adj.hoursAdjusted;
  1364→        }
  1365→      }
  1366→    }
  1367→
  1368→    // Recalculate metrics for all weeks
  1369→    for (const p of leveled) {
  1370→      p.variance = p.available.total - p.required.total;
  1371→      p.utilizationPct = p.available.total > 0 ? p.required.total / p.available.total : 0;
  1372→      p.isOverloaded = p.utilizationPct > MAX_UTILIZATION;
  1373→      p.isUnderutilized = p.utilizationPct < MIN_UTILIZATION;
  1374→    }
  1375→
  1376→    return leveled;
  1377→  }
  1378→
  1379→  /**
  1380→   * Calculate aggregate metrics
  1381→   */
  1382→  private calculateMetrics(projections: ProjectionData[]): LevelingMetrics {
  1383→    if (projections.length === 0) {
  1384→      return {
  1385→        avgUtilization: 0,
  1386→        minUtilization: 0,
  1387→        maxUtilization: 0,
