  1421→  }
  1422→
  1423→  // ===========================================================================
  1424→  // Private: Persistence
  1425→  // ===========================================================================
  1426→
  1427→  /**
  1428→   * Persist projections and adjustments to database
  1429→   */
  1430→  private async persistProjections(
  1431→    runId: string,
  1432→    projections: ProjectionData[],
  1433→    adjustments: ProposedAdjustment[]
  1434→  ): Promise<void> {
  1435→    await this.inTransaction('persistProjections', async (tx, span) => {
