/**
 * MMS Man-hour Leveling Service
 *
 * Projects workforce requirements and generates adjustment recommendations
 * to balance workload across time periods. Prevents overload/underutilization
 * of depot maintenance resources over the tactical planning horizon.
 *
 * Key responsibilities:
 * - Calculate raw man-hour projections from PM schedule
 * - Identify overloaded and underutilized weeks
 * - Apply leveling strategies in priority order
 * - Persist projections and adjustments
 * - Support approval workflow for adjustments
 *
 * Leveling Strategies (priority order):
 * 1. ADVANCE_PM (1.1x cost, LOW risk, max 40h/week)
 * 2. DEFER_PM (1.05x cost, LOW risk, max 40h/week)
 * 3. ADD_OVERTIME (1.5x cost, NO risk, max 80h/week)
 * 4. CROSS_DEPOT (1.3x cost, MEDIUM risk, max 60h/week)
 * 5. ADD_CONTRACTOR (2.0x cost, MEDIUM risk, max 100h/week)
 * 6. MANUAL_REVIEW (flagged for high unresolvable overload)
 *
 * Utilization Targets:
 * - Target: 85%
 * - Minimum: 70% (underutilized below this)
 * - Maximum: 100% (overloaded above this)
 *
 * @see specs/004-domain-services.md Section 4.6
 */

import {
  eq,
  and,
  gte,
  lte,
  desc,
  asc,
  sql,
  inArray,
  isNull,
  or,
  count,
  type SQL,
} from 'drizzle-orm';
import {
  addDays,
  addWeeks,
  startOfWeek,
  endOfWeek,
  format,
  differenceInWeeks,
  parseISO,
  isBefore,
  isAfter,
} from 'date-fns';
import { BaseService } from '../lib/services/base';
import {
  manhourCapacity,
  manhourProjections,
  manhourAdjustments,
  pmSchedule,
  pmTypes,
  depots,
  trains,
  laborRates,
  type ManhourCapacity,
  type ManhourProjection,
  type ManhourAdjustment,
} from '../lib/db/schema';
import { NotFoundError, ValidationError, ConflictError } from '../lib/errors';

// =============================================================================
// Constants
// =============================================================================

/** Minimum utilization percentage (underutilized below this) */
const MIN_UTILIZATION = 0.7;

/** Maximum utilization percentage (overloaded above this) */
const MAX_UTILIZATION = 1.0;

/** Default base labor rate per hour (SGD) */
const DEFAULT_BASE_RATE = 85;

/** Minimum meaningful shift in hours (don't bother with tiny adjustments) */
const MIN_SHIFT_HOURS = 8;

/** Minimum overtime hours to add */
const MIN_OVERTIME_HOURS = 4;

// =============================================================================
// Types
// =============================================================================

/** Leveling strategy types */
export type AdjustmentType =
  | 'ADVANCE_PM'
  | 'DEFER_PM'
  | 'ADD_OVERTIME'
  | 'CROSS_DEPOT'
  | 'ADD_CONTRACTOR'
  | 'MANUAL_REVIEW';

/** Risk levels for adjustments */
export type RiskLevel = 'NONE' | 'LOW' | 'MEDIUM' | 'HIGH';

/** Adjustment status in workflow */
export type AdjustmentStatus = 'PROPOSED' | 'APPROVED' | 'REJECTED' | 'APPLIED';

/** Leveling strategy configuration */
export interface LevelingStrategy {
  type: AdjustmentType;
  priority: number;
  maxHoursPerWeek: number;
  costMultiplier: number;
  riskLevel: RiskLevel;
}

/** All leveling strategies in priority order */
export const LEVELING_STRATEGIES: LevelingStrategy[] = [
  { type: 'ADVANCE_PM', priority: 1, maxHoursPerWeek: 40, costMultiplier: 1.1, riskLevel: 'LOW' },
  { type: 'DEFER_PM', priority: 2, maxHoursPerWeek: 40, costMultiplier: 1.05, riskLevel: 'LOW' },
  { type: 'ADD_OVERTIME', priority: 3, maxHoursPerWeek: 80, costMultiplier: 1.5, riskLevel: 'NONE' },
  { type: 'CROSS_DEPOT', priority: 4, maxHoursPerWeek: 60, costMultiplier: 1.3, riskLevel: 'MEDIUM' },
  {
    type: 'ADD_CONTRACTOR',
    priority: 5,
    maxHoursPerWeek: 100,
    costMultiplier: 2.0,
    riskLevel: 'MEDIUM',
  },
];

/** Time period for projections */
export interface LevelingTimePeriod {
  start: Date;
  end: Date;
}

/** Required hours breakdown */
export interface RequiredHours {
  pm: number;
  corrective: number;
  overhaul: number;
  total: number;
}

/** Available hours breakdown */
export interface AvailableHours {
  regular: number;
  overtime: number;
  total: number;
}

/** Projection data for a single week/period */
export interface ProjectionData {
  depotId: string;
  depotCode?: string;
  week: Date;
  granularity: 'WEEKLY' | 'MONTHLY';
  required: RequiredHours;
  available: AvailableHours;
  variance: number;
  utilizationPct: number;
  isOverloaded: boolean;
  isUnderutilized: boolean;
}

/** Proposed adjustment */
export interface ProposedAdjustment {
  type: AdjustmentType;
  sourcePeriod: LevelingTimePeriod;
  targetPeriod?: LevelingTimePeriod;
  hoursAdjusted: number;
  affectedPMs: string[];
  affectedTrains: string[];
  costImpact: number;
  riskLevel: RiskLevel;
  reason: string;
}

/** Leveling metrics */
export interface LevelingMetrics {
  avgUtilization: number;
  minUtilization: number;
  maxUtilization: number;
  overloadedWeeks: number;
  underutilizedWeeks: number;
  totalRequiredHours: number;
  totalAvailableHours: number;
}

/** Improvement summary after leveling */
export interface LevelingImprovement {
  utilizationDelta: number;
  overloadedWeeksReduced: number;
  underutilizedWeeksReduced: number;
  totalCostImpact: number;
}

/** Full leveling result */
export interface LevelingResult {
  projectionRunId: string;
  generatedAt: Date;
  horizonWeeks: number;
  depotIds: string[];
  original: {
    projections: ProjectionData[];
    metrics: LevelingMetrics;
  };
  leveled: {
    projections: ProjectionData[];
    metrics: LevelingMetrics;
  };
  adjustments: ProposedAdjustment[];
  improvement: LevelingImprovement;
}

/** PM shiftable info */
interface ShiftablePM {
  id: string;
  trainId: string;
  pmTypeCode: string;
  estimatedHours: number;
  currentDate: Date;
  constraintStart: Date;
  constraintEnd: Date;
}

/** Depot with capacity for cross-depot leveling */
interface DepotWithCapacity {
  depotId: string;
  depotCode: string;
  depotName: string;
  availableHours: number;
}

/** Request for generating projections */
export interface GenerateProjectionsRequest {
  horizonWeeks?: number;
  depotIds?: string[];
  granularity?: 'WEEKLY' | 'MONTHLY';
}

/** Capacity configuration request */
export interface UpdateCapacityRequest {
  depotId: string;
  effectiveFrom: Date;
  effectiveTo?: Date;
  dayShiftHours: number;
  nightShiftHours?: number;
  weekendHours?: number;
  techniciansDay: number;
  techniciansNight?: number;
  specialists?: number;
  maxOvertimePct?: number;
  minUtilizationPct?: number;
  targetUtilizationPct?: number;
  notes?: string;
}

/** Filters for querying projections */
export interface ProjectionFilters {
  depotId?: string;
  fromDate?: Date;
  toDate?: Date;
  isOverloaded?: boolean;
  isUnderutilized?: boolean;
  projectionRunId?: string;
}

/** Filters for querying adjustments */
export interface AdjustmentFilters {
  depotId?: string;
  status?: AdjustmentStatus;
  type?: AdjustmentType;
  fromDate?: Date;
  toDate?: Date;
}

/** Paginated result */
export interface PaginatedResult<T> {
  data: T[];
  total: number;
  page: number;
  pageSize: number;
}

// =============================================================================
// Service Singleton
// =============================================================================

let serviceInstance: ManHourLevelingService | null = null;

/**
 * Get singleton instance of ManHourLevelingService
 */
export function getManHourLevelingService(): ManHourLevelingService {
  if (!serviceInstance) {
    serviceInstance = new ManHourLevelingService();
  }
  return serviceInstance;
}

// =============================================================================
// Service Implementation
// =============================================================================

/**
 * ManHourLevelingService
 *
 * Projects workforce requirements and generates adjustment recommendations
 * to balance workload across time periods.
 */
export class ManHourLevelingService extends BaseService {
  constructor() {
    super({ name: 'man-hour-leveling-service' });
  }

  // ===========================================================================
  // Main Operations
  // ===========================================================================

  /**
   * Generate projections and leveling recommendations
   *
   * This is the main entry point for the leveling engine.
   * It calculates raw projections, identifies imbalances, generates adjustments,
   * and persists the results.
   */
  async generateProjections(request: GenerateProjectionsRequest = {}): Promise<LevelingResult> {
    const horizonWeeks = request.horizonWeeks ?? 12;
    const granularity = request.granularity ?? 'WEEKLY';

    return this.traced(
      'generateProjections',
      async (span) => {
        span.setAttribute('mms.manhour.horizon_weeks', horizonWeeks);
        span.setAttribute('mms.manhour.granularity', granularity);

        const runId = crypto.randomUUID();
        span.setAttribute('mms.manhour.run_id', runId);

        // 1. Get depots to process
        const depotIds = await this.resolveDepotIds(request.depotIds);
        if (depotIds.length === 0) {
          throw new ValidationError('No depots found for projection');
        }
        span.setAttribute('mms.manhour.depot_count', depotIds.length);

        // 2. Calculate raw projections
        const rawProjections = await this.calculateRawProjections(
          depotIds,
          horizonWeeks,
          granularity
        );

        // 3. Identify imbalances
        const imbalances = this.identifyImbalances(rawProjections);
        span.setAttribute('overloadedWeeks', imbalances.overloaded.length);
        span.setAttribute('underutilizedWeeks', imbalances.underutilized.length);

        // 4. Generate adjustments using multiple strategies
        const adjustments = await this.generateAdjustments(rawProjections);
        span.setAttribute('adjustmentCount', adjustments.length);

        // 5. Apply adjustments to get leveled projections
        const leveledProjections = this.applyAdjustments(rawProjections, adjustments);

        // 6. Calculate metrics
        const originalMetrics = this.calculateMetrics(rawProjections);
        const leveledMetrics = this.calculateMetrics(leveledProjections);

        // 7. Persist projections and adjustments
        await this.persistProjections(runId, rawProjections, adjustments);

        // 8. Build result
        const improvement: LevelingImprovement = {
          utilizationDelta: leveledMetrics.avgUtilization - originalMetrics.avgUtilization,
          overloadedWeeksReduced: originalMetrics.overloadedWeeks - leveledMetrics.overloadedWeeks,
          underutilizedWeeksReduced:
            originalMetrics.underutilizedWeeks - leveledMetrics.underutilizedWeeks,
          totalCostImpact: adjustments.reduce((sum, a) => sum + a.costImpact, 0),
        };

        this.log.info(
          {
            runId,
            horizonWeeks,
            depotCount: depotIds.length,
            adjustmentCount: adjustments.length,
            improvement,
          },
          'Generated man-hour projections'
        );

        return {
          projectionRunId: runId,
          generatedAt: new Date(),
          horizonWeeks,
          depotIds,
          original: { projections: rawProjections, metrics: originalMetrics },
          leveled: { projections: leveledProjections, metrics: leveledMetrics },
          adjustments,
          improvement,
        };
      },
      { 'mms.manhour.requested_depots': request.depotIds?.length ?? 0 }
    );
  }

  /**
   * Get projections for a specific depot and time range
   */
  async getProjections(
    filters: ProjectionFilters,
    page = 1,
    pageSize = 50
  ): Promise<PaginatedResult<ManhourProjection>> {
    return this.traced('getProjections', async () => {
      const conditions: SQL<unknown>[] = [];

      if (filters.depotId) {
        conditions.push(eq(manhourProjections.depotId, filters.depotId));
      }
      if (filters.fromDate) {
        conditions.push(gte(manhourProjections.periodStart, format(filters.fromDate, 'yyyy-MM-dd')));
      }
      if (filters.toDate) {
        conditions.push(lte(manhourProjections.periodEnd, format(filters.toDate, 'yyyy-MM-dd')));
      }
      if (filters.projectionRunId) {
        conditions.push(eq(manhourProjections.projectionRunId, filters.projectionRunId));
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      const [projections, totalResult] = await Promise.all([
        this.db.query.manhourProjections.findMany({
          where: whereClause,
          orderBy: [asc(manhourProjections.periodStart)],
          limit: pageSize,
          offset: (page - 1) * pageSize,
        }),
        this.db.select({ count: count() }).from(manhourProjections).where(whereClause),
      ]);

      return {
        data: projections,
        total: totalResult[0]?.count ?? 0,
        page,
        pageSize,
      };
    });
  }

  /**
   * Get adjustments with optional filters
   */
  async getAdjustments(
    filters: AdjustmentFilters,
    page = 1,
    pageSize = 50
  ): Promise<PaginatedResult<ManhourAdjustment>> {
    return this.traced('getAdjustments', async () => {
      const conditions: SQL<unknown>[] = [];

      if (filters.status) {
        conditions.push(eq(manhourAdjustments.status, filters.status));
      }
      if (filters.type) {
        conditions.push(eq(manhourAdjustments.adjustmentType, filters.type));
      }
      if (filters.fromDate) {
        conditions.push(
          gte(manhourAdjustments.sourcePeriodStart, format(filters.fromDate, 'yyyy-MM-dd'))
        );
      }
      if (filters.toDate) {
        conditions.push(
          lte(manhourAdjustments.sourcePeriodEnd, format(filters.toDate, 'yyyy-MM-dd'))
        );
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      const [adjustments, totalResult] = await Promise.all([
        this.db.query.manhourAdjustments.findMany({
          where: whereClause,
          orderBy: [desc(manhourAdjustments.createdAt)],
          limit: pageSize,
          offset: (page - 1) * pageSize,
        }),
        this.db.select({ count: count() }).from(manhourAdjustments).where(whereClause),
      ]);

      return {
        data: adjustments,
        total: totalResult[0]?.count ?? 0,
        page,
        pageSize,
      };
    });
  }

  /**
   * Approve an adjustment
   */
  async approveAdjustment(adjustmentId: string, userId: string): Promise<ManhourAdjustment> {
    return this.inTransaction('approveAdjustment', async (tx, span) => {
      span.setAttribute('adjustmentId', adjustmentId);
      span.setAttribute('userId', userId);

      // Get adjustment
      const adjustment = await tx.query.manhourAdjustments.findFirst({
        where: eq(manhourAdjustments.id, adjustmentId),
      });

      if (!adjustment) {
        throw new NotFoundError(`Adjustment ${adjustmentId} not found`);
      }

      if (adjustment.status !== 'PROPOSED') {
        throw new ConflictError(
          `Cannot approve adjustment in ${adjustment.status} status`,
          { errorCode: 'ADJUSTMENT_STATUS_INVALID', currentStatus: adjustment.status }
        );
      }

      // Update status
      const [updated] = await tx
        .update(manhourAdjustments)
        .set({
          status: 'APPROVED',
          approvedBy: userId,
          approvedAt: new Date(),
        })
        .where(eq(manhourAdjustments.id, adjustmentId))
        .returning();

      this.log.info({ adjustmentId, userId, type: adjustment.adjustmentType }, 'Adjustment approved');

      return updated;
    });
  }

  /**
   * Reject an adjustment
   */
  async rejectAdjustment(
    adjustmentId: string,
    userId: string,
    reason: string
  ): Promise<ManhourAdjustment> {
    return this.inTransaction('rejectAdjustment', async (tx, span) => {
      span.setAttribute('adjustmentId', adjustmentId);
      span.setAttribute('userId', userId);

      // Get adjustment
      const adjustment = await tx.query.manhourAdjustments.findFirst({
        where: eq(manhourAdjustments.id, adjustmentId),
      });

      if (!adjustment) {
        throw new NotFoundError(`Adjustment ${adjustmentId} not found`);
      }

      if (adjustment.status !== 'PROPOSED') {
        throw new ConflictError(
          `Cannot reject adjustment in ${adjustment.status} status`,
          { errorCode: 'ADJUSTMENT_STATUS_INVALID', currentStatus: adjustment.status }
        );
      }

      // Update status
      const [updated] = await tx
        .update(manhourAdjustments)
        .set({
          status: 'REJECTED',
          approvedBy: userId,
          approvedAt: new Date(),
          rejectionReason: reason,
        })
        .where(eq(manhourAdjustments.id, adjustmentId))
        .returning();

      this.log.info(
        { adjustmentId, userId, type: adjustment.adjustmentType, reason },
        'Adjustment rejected'
      );

      return updated;
    });
  }

  // ===========================================================================
  // Capacity Management
  // ===========================================================================

  /**
   * Get capacity configuration for a depot
   */
  async getCapacity(depotId: string, asOfDate?: Date): Promise<ManhourCapacity | null> {
    return this.traced('getCapacity', async (span) => {
      span.setAttribute('mms.depot.id', depotId);

      const dateStr = format(asOfDate ?? new Date(), 'yyyy-MM-dd');

      const capacity = await this.db.query.manhourCapacity.findFirst({
        where: and(
          eq(manhourCapacity.depotId, depotId),
          lte(manhourCapacity.effectiveFrom, dateStr),
          or(isNull(manhourCapacity.effectiveTo), gte(manhourCapacity.effectiveTo, dateStr))
        ),
        orderBy: [desc(manhourCapacity.effectiveFrom)],
      });

      return capacity ?? null;
    });
  }

  /**
   * Update or create capacity configuration
   */
  async updateCapacity(request: UpdateCapacityRequest): Promise<ManhourCapacity> {
    return this.inTransaction('updateCapacity', async (tx, span) => {
      span.setAttribute('mms.depot.id', request.depotId);

      // Check depot exists
      const depot = await tx.query.depots.findFirst({
        where: eq(depots.id, request.depotId),
      });

      if (!depot) {
        throw new NotFoundError(`Depot ${request.depotId} not found`);
      }

      // Close any existing capacity that overlaps
      const effectiveFromStr = format(request.effectiveFrom, 'yyyy-MM-dd');
      await tx
        .update(manhourCapacity)
        .set({
          effectiveTo: format(addDays(request.effectiveFrom, -1), 'yyyy-MM-dd'),
          updatedAt: new Date(),
        })
        .where(
          and(
            eq(manhourCapacity.depotId, request.depotId),
            lte(manhourCapacity.effectiveFrom, effectiveFromStr),
            or(isNull(manhourCapacity.effectiveTo), gte(manhourCapacity.effectiveTo, effectiveFromStr))
          )
        );

      // Insert new capacity
      const [newCapacity] = await tx
        .insert(manhourCapacity)
        .values({
          depotId: request.depotId,
          effectiveFrom: effectiveFromStr,
          effectiveTo: request.effectiveTo ? format(request.effectiveTo, 'yyyy-MM-dd') : null,
          dayShiftHours: String(request.dayShiftHours),
          nightShiftHours: String(request.nightShiftHours ?? 0),
          weekendHours: String(request.weekendHours ?? 0),
          techniciansDay: request.techniciansDay,
          techniciansNight: request.techniciansNight ?? 0,
          specialists: request.specialists ?? 0,
          maxOvertimePct: String(request.maxOvertimePct ?? 20),
          minUtilizationPct: String(request.minUtilizationPct ?? 70),
          targetUtilizationPct: String(request.targetUtilizationPct ?? 85),
          notes: request.notes,
        })
        .returning();

      this.log.info(
        { depotId: request.depotId, effectiveFrom: effectiveFromStr },
        'Updated depot capacity configuration'
      );

      return newCapacity;
    });
  }

  // ===========================================================================
  // Private: Projection Calculation
  // ===========================================================================

  private async resolveDepotIds(requestedIds?: string[]): Promise<string[]> {
    if (requestedIds && requestedIds.length > 0) {
      return requestedIds;
    }

    // Get all active depots
    const allDepots = await this.db.query.depots.findMany({
      columns: { id: true },
    });

    return allDepots.map((d) => d.id);
  }

  /**
   * Calculate raw man-hour projections from PM schedule
   */
  private async calculateRawProjections(
    depotIds: string[],
    horizonWeeks: number,
    granularity: 'WEEKLY' | 'MONTHLY'
  ): Promise<ProjectionData[]> {
    const projections: ProjectionData[] = [];
    const now = new Date();
    const startDate = startOfWeek(now, { weekStartsOn: 1 }); // Monday

    // Get depot info
    const depotList = await this.db.query.depots.findMany({
      where: inArray(depots.id, depotIds),
    });
    const depotMap = new Map(depotList.map((d) => [d.id, d]));

    for (const depotId of depotIds) {
      const depot = depotMap.get(depotId);
      if (!depot) continue;

      // Get capacity for depot
      const capacity = await this.getCapacity(depotId);
      const weeklyCapacity = this.calculateWeeklyCapacity(capacity);

      for (let weekOffset = 0; weekOffset < horizonWeeks; weekOffset++) {
        const weekStart = addWeeks(startDate, weekOffset);
        const weekEnd = endOfWeek(weekStart, { weekStartsOn: 1 });

        // Get PM hours for this week
        const pmHours = await this.getPmHoursForPeriod(depotId, weekStart, weekEnd);

        // Calculate available hours
        const regularHours = weeklyCapacity.regular;
        const overtimeMax =
          regularHours * (capacity ? parseFloat(capacity.maxOvertimePct ?? '20') / 100 : 0.2);

        const required: RequiredHours = {
          pm: pmHours,
          corrective: 0, // TODO: Integrate with unavailability events
          overhaul: 0, // TODO: Separate overhaul tracking
          total: pmHours,
        };

        const available: AvailableHours = {
          regular: regularHours,
          overtime: overtimeMax,
          total: regularHours + overtimeMax,
        };

        const variance = available.total - required.total;
        const utilizationPct = available.total > 0 ? required.total / available.total : 0;

        projections.push({
          depotId,
          depotCode: depot.code,
          week: weekStart,
          granularity,
          required,
          available,
          variance,
          utilizationPct,
          isOverloaded: utilizationPct > MAX_UTILIZATION,
          isUnderutilized: utilizationPct < MIN_UTILIZATION,
        });
      }
    }

    return projections;
  }

  /**
   * Calculate weekly capacity from configuration
   */
  private calculateWeeklyCapacity(
    capacity: ManhourCapacity | null
  ): { regular: number; overtime: number } {
    if (!capacity) {
      // Default capacity when not configured
      return { regular: 200, overtime: 40 };
    }

    const dayHours = parseFloat(capacity.dayShiftHours ?? '0');
    const nightHours = parseFloat(capacity.nightShiftHours ?? '0');
    const weekendHours = parseFloat(capacity.weekendHours ?? '0');
    const maxOvertimePct = parseFloat(capacity.maxOvertimePct ?? '20') / 100;

    const regular = dayHours * 5 + nightHours * 5 + weekendHours * 2;
    const overtime = regular * maxOvertimePct;

    return { regular, overtime };
  }

  /**
   * Get total PM hours for a time period
   */
  private async getPmHoursForPeriod(
    depotId: string,
    startDate: Date,
    endDate: Date
  ): Promise<number> {
    const startStr = format(startDate, 'yyyy-MM-dd');
    const endStr = format(endDate, 'yyyy-MM-dd');

    // Get scheduled PMs for the period
    const scheduledPMs = await this.db
      .select({
        pmTypeId: pmSchedule.pmTypeId,
        count: count(),
      })
      .from(pmSchedule)
      .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
      .where(
        and(
          eq(trains.currentDepotId, depotId),
          gte(pmSchedule.targetDate, startStr),
          lte(pmSchedule.targetDate, endStr),
          eq(pmSchedule.status, 'SCHEDULED'),
          isNull(pmSchedule.scenarioId) // Only real schedule, not scenarios
        )
      )
      .groupBy(pmSchedule.pmTypeId);

    if (scheduledPMs.length === 0) {
      return 0;
    }

    // Get estimated hours for each PM type
    const pmTypeIds = scheduledPMs.map((p) => p.pmTypeId);
    const pmTypeHours = await this.db.query.pmTypes.findMany({
      where: inArray(pmTypes.id, pmTypeIds),
      columns: { id: true, estimatedHours: true },
    });

    const hoursMap = new Map(pmTypeHours.map((pt) => [pt.id, parseFloat(pt.estimatedHours ?? '0')]));

    // Calculate total hours
    let totalHours = 0;
    for (const pm of scheduledPMs) {
      const hours = hoursMap.get(pm.pmTypeId) ?? 0;
      totalHours += hours * pm.count;
    }

    return totalHours;
  }

  // ===========================================================================
  // Private: Imbalance Detection
  // ===========================================================================

  /**
   * Identify overloaded and underutilized weeks
   */
  private identifyImbalances(projections: ProjectionData[]): {
    overloaded: ProjectionData[];
    underutilized: ProjectionData[];
  } {
    return {
      overloaded: projections.filter((p) => p.isOverloaded),
      underutilized: projections.filter((p) => p.isUnderutilized),
    };
  }

  // ===========================================================================
  // Private: Adjustment Generation
  // ===========================================================================

  /**
   * Generate adjustments to level workload
   */
  private async generateAdjustments(
    projections: ProjectionData[]
  ): Promise<ProposedAdjustment[]> {
    const adjustments: ProposedAdjustment[] = [];

    // Group projections by depot
    const byDepot = this.groupByDepot(projections);

    for (const depotProjections of byDepot.values()) {
      const overloaded = depotProjections.filter((p) => p.isOverloaded);
      const underutilized = depotProjections.filter((p) => p.isUnderutilized);

      // Track remaining capacity in underutilized weeks
      const underutilizedCapacity = new Map(
        underutilized.map((p) => [
          p.week.toISOString(),
          p.available.total - p.required.total,
        ])
      );

      for (const overWeek of overloaded) {
        let remainingExcess = overWeek.required.total - overWeek.available.total;

        // Try each strategy in priority order
        for (const strategy of LEVELING_STRATEGIES) {
          if (remainingExcess <= 0) break;

          const adjustment = await this.tryStrategy(
            strategy,
            overWeek,
            underutilized,
            underutilizedCapacity,
            depotProjections,
            remainingExcess
          );

          if (adjustment) {
            adjustments.push(adjustment);
            remainingExcess -= adjustment.hoursAdjusted;

            // Update underutilized capacity if we used some
            if (
              adjustment.targetPeriod &&
              (adjustment.type === 'ADVANCE_PM' || adjustment.type === 'DEFER_PM')
            ) {
              const key = adjustment.targetPeriod.start.toISOString();
              const current = underutilizedCapacity.get(key) ?? 0;
              underutilizedCapacity.set(key, current - adjustment.hoursAdjusted);
            }
          }
        }

        // If still overloaded, flag for manual review
        if (remainingExcess > 0) {
          adjustments.push({
            type: 'MANUAL_REVIEW',
            sourcePeriod: {
              start: overWeek.week,
              end: addDays(overWeek.week, 7),
            },
            hoursAdjusted: 0,
            affectedPMs: [],
            affectedTrains: [],
            costImpact: 0,
            riskLevel: 'HIGH',
            reason: `Unable to resolve ${remainingExcess.toFixed(0)}h overload - requires manual intervention`,
          });
        }
      }
    }

    return adjustments;
  }

  /**
   * Try a specific leveling strategy
   */
  private async tryStrategy(
    strategy: LevelingStrategy,
    overloadedWeek: ProjectionData,
    underutilizedWeeks: ProjectionData[],
    underutilizedCapacity: Map<string, number>,
    allProjections: ProjectionData[],
    excessHours: number
  ): Promise<ProposedAdjustment | null> {
    const maxHours = Math.min(strategy.maxHoursPerWeek, excessHours);
    const baseRate = await this.getBaseRate(overloadedWeek.depotId);

    switch (strategy.type) {
      case 'ADVANCE_PM':
      case 'DEFER_PM':
        return this.tryShiftPmStrategy(
          strategy,
          overloadedWeek,
          underutilizedWeeks,
          underutilizedCapacity,
          maxHours,
          baseRate
        );

      case 'ADD_OVERTIME':
        return this.tryOvertimeStrategy(strategy, overloadedWeek, maxHours, baseRate);

      case 'CROSS_DEPOT':
        return this.tryCrossDepotStrategy(strategy, overloadedWeek, maxHours, baseRate);

      case 'ADD_CONTRACTOR':
        return this.tryContractorStrategy(strategy, overloadedWeek, maxHours, baseRate);

      default:
        return null;
    }
  }

  /**
   * Try ADVANCE_PM or DEFER_PM strategy
   */
  private async tryShiftPmStrategy(
    strategy: LevelingStrategy,
    overloadedWeek: ProjectionData,
    underutilizedWeeks: ProjectionData[],
    underutilizedCapacity: Map<string, number>,
    maxHours: number,
    baseRate: number
  ): Promise<ProposedAdjustment | null> {
    const direction = strategy.type === 'ADVANCE_PM' ? -1 : 1;

    // Find candidate weeks (before for ADVANCE, after for DEFER)
    const candidates = underutilizedWeeks
      .filter((w) => {
        const weekDiff = differenceInWeeks(w.week, overloadedWeek.week);
        const remainingCapacity = underutilizedCapacity.get(w.week.toISOString()) ?? 0;
        return (
          w.depotId === overloadedWeek.depotId &&
          weekDiff * direction > 0 &&
          Math.abs(weekDiff) <= 4 &&
          remainingCapacity > MIN_SHIFT_HOURS
        );
      })
      .sort(
        (a, b) =>
          Math.abs(differenceInWeeks(a.week, overloadedWeek.week)) -
          Math.abs(differenceInWeeks(b.week, overloadedWeek.week))
      );

    for (const candidate of candidates) {
      const availableCapacity = underutilizedCapacity.get(candidate.week.toISOString()) ?? 0;
      const shiftHours = Math.min(maxHours, availableCapacity * 0.8);

      if (shiftHours >= MIN_SHIFT_HOURS) {
        // Find PMs that can be shifted
        const shiftablePMs = await this.findShiftablePMs(
          overloadedWeek,
          candidate,
          shiftHours,
          strategy.type as 'ADVANCE_PM' | 'DEFER_PM'
        );

        if (shiftablePMs.length > 0) {
          const actualHours = shiftablePMs.reduce((sum, pm) => sum + pm.estimatedHours, 0);

          const weekNumSource = format(overloadedWeek.week, 'ww');
          const weekNumTarget = format(candidate.week, 'ww');
          const action = strategy.type === 'DEFER_PM' ? 'Defer' : 'Advance';

          return {
            type: strategy.type,
            sourcePeriod: {
              start: overloadedWeek.week,
              end: addDays(overloadedWeek.week, 7),
            },
            targetPeriod: {
              start: candidate.week,
              end: addDays(candidate.week, 7),
            },
            hoursAdjusted: actualHours,
            affectedPMs: shiftablePMs.map((pm) => pm.id),
            affectedTrains: [...new Set(shiftablePMs.map((pm) => pm.trainId))],
            costImpact: actualHours * baseRate * (strategy.costMultiplier - 1),
            riskLevel: strategy.riskLevel,
            reason: `${action} ${actualHours.toFixed(0)}h (${shiftablePMs.length} PMs) from Week ${weekNumSource} to Week ${weekNumTarget}`,
          };
        }
      }
    }

    return null;
  }

  /**
   * Try ADD_OVERTIME strategy
   */
  private tryOvertimeStrategy(
    strategy: LevelingStrategy,
    overloadedWeek: ProjectionData,
    maxHours: number,
    baseRate: number
  ): ProposedAdjustment | null {
    const availableOvertime = overloadedWeek.available.overtime;
    const overtimeHours = Math.min(maxHours, availableOvertime);

    if (overtimeHours >= MIN_OVERTIME_HOURS) {
      const weekNum = format(overloadedWeek.week, 'ww');

      return {
        type: 'ADD_OVERTIME',
        sourcePeriod: {
          start: overloadedWeek.week,
          end: addDays(overloadedWeek.week, 7),
        },
        targetPeriod: {
          start: overloadedWeek.week,
          end: addDays(overloadedWeek.week, 7),
        },
        hoursAdjusted: overtimeHours,
        affectedPMs: [],
        affectedTrains: [],
        costImpact: overtimeHours * baseRate * (strategy.costMultiplier - 1),
        riskLevel: strategy.riskLevel,
        reason: `Add ${overtimeHours.toFixed(0)}h overtime in Week ${weekNum}`,
      };
    }

    return null;
  }

  /**
   * Try CROSS_DEPOT strategy
   */
  private async tryCrossDepotStrategy(
    strategy: LevelingStrategy,
    overloadedWeek: ProjectionData,
    maxHours: number,
    baseRate: number
  ): Promise<ProposedAdjustment | null> {
    const otherDepots = await this.findDepotsWithCapacity(
      overloadedWeek.week,
      maxHours,
      overloadedWeek.depotId
    );

    if (otherDepots.length > 0) {
      const best = otherDepots[0];
      const weekNum = format(overloadedWeek.week, 'ww');

      return {
        type: 'CROSS_DEPOT',
        sourcePeriod: {
          start: overloadedWeek.week,
          end: addDays(overloadedWeek.week, 7),
        },
        targetPeriod: {
          start: overloadedWeek.week,
          end: addDays(overloadedWeek.week, 7),
        },
        hoursAdjusted: best.availableHours,
        affectedPMs: [],
        affectedTrains: [],
        costImpact: best.availableHours * baseRate * (strategy.costMultiplier - 1),
        riskLevel: strategy.riskLevel,
        reason: `Request ${best.availableHours.toFixed(0)}h support from ${best.depotName} in Week ${weekNum}`,
      };
    }

    return null;
  }

  /**
   * Try ADD_CONTRACTOR strategy
   */
  private tryContractorStrategy(
    strategy: LevelingStrategy,
    overloadedWeek: ProjectionData,
    maxHours: number,
    baseRate: number
  ): ProposedAdjustment {
    const weekNum = format(overloadedWeek.week, 'ww');

    return {
      type: 'ADD_CONTRACTOR',
      sourcePeriod: {
        start: overloadedWeek.week,
        end: addDays(overloadedWeek.week, 7),
      },
      targetPeriod: {
        start: overloadedWeek.week,
        end: addDays(overloadedWeek.week, 7),
      },
      hoursAdjusted: maxHours,
      affectedPMs: [],
      affectedTrains: [],
      costImpact: maxHours * baseRate * (strategy.costMultiplier - 1),
      riskLevel: strategy.riskLevel,
      reason: `Engage contractor for ${maxHours.toFixed(0)}h in Week ${weekNum}`,
    };
  }

  /**
   * Find PMs that can be shifted to another week
   */
  private async findShiftablePMs(
    fromWeek: ProjectionData,
    toWeek: ProjectionData,
    targetHours: number,
    strategy: 'ADVANCE_PM' | 'DEFER_PM'
  ): Promise<ShiftablePM[]> {
    const fromStart = format(fromWeek.week, 'yyyy-MM-dd');
    const fromEnd = format(addDays(fromWeek.week, 6), 'yyyy-MM-dd');

    // Get PMs in the overloaded week
    const scheduledPMs = await this.db
      .select({
        id: pmSchedule.id,
        trainId: pmSchedule.trainId,
        pmTypeId: pmSchedule.pmTypeId,
        targetDate: pmSchedule.targetDate,
        constraintStart: pmSchedule.constraintStart,
        constraintEnd: pmSchedule.constraintEnd,
        isLocked: pmSchedule.isLocked,
      })
      .from(pmSchedule)
      .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
      .where(
        and(
          eq(trains.currentDepotId, fromWeek.depotId),
          gte(pmSchedule.targetDate, fromStart),
          lte(pmSchedule.targetDate, fromEnd),
          inArray(pmSchedule.status, ['SCHEDULED']), // Not CONFIRMED, IN_PROGRESS, or COMPLETED
          eq(pmSchedule.isLocked, false), // Not locked
          isNull(pmSchedule.scenarioId) // Real schedule
        )
      );

    if (scheduledPMs.length === 0) {
      return [];
    }

    // Get PM type info
    const pmTypeIds = [...new Set(scheduledPMs.map((p) => p.pmTypeId))];
    const pmTypeInfo = await this.db.query.pmTypes.findMany({
      where: inArray(pmTypes.id, pmTypeIds),
      columns: { id: true, pmCode: true, estimatedHours: true },
    });
    const typeMap = new Map(pmTypeInfo.map((pt) => [pt.id, pt]));

    // Filter PMs that can be shifted to target week
    const shiftablePMs: ShiftablePM[] = [];
    let accumulatedHours = 0;

    for (const pm of scheduledPMs) {
      if (accumulatedHours >= targetHours) break;

      const pmType = typeMap.get(pm.pmTypeId);
      if (!pmType) continue;

      const constraintStart = pm.constraintStart ? parseISO(pm.constraintStart) : null;
      const constraintEnd = pm.constraintEnd ? parseISO(pm.constraintEnd) : null;

      // Check if target week is within compliance window
      const targetDate = strategy === 'ADVANCE_PM' ? toWeek.week : addDays(toWeek.week, 6);

      const withinWindow =
        (!constraintStart || !isBefore(targetDate, constraintStart)) &&
        (!constraintEnd || !isAfter(targetDate, constraintEnd));

      if (withinWindow) {
        const hours = parseFloat(pmType.estimatedHours ?? '0');
        shiftablePMs.push({
          id: pm.id,
          trainId: pm.trainId,
          pmTypeCode: pmType.pmCode,
          estimatedHours: hours,
          currentDate: parseISO(pm.targetDate),
          constraintStart: constraintStart ?? new Date(0),
          constraintEnd: constraintEnd ?? new Date(9999, 11, 31),
        });
        accumulatedHours += hours;
      }
    }

    return shiftablePMs;
  }

  /**
   * Find other depots with available capacity
   */
  private async findDepotsWithCapacity(
    week: Date,
    minHours: number,
    excludeDepotId: string
  ): Promise<DepotWithCapacity[]> {
    // Get all depots except the excluded one
    const otherDepots = await this.db.query.depots.findMany({
      where: sql`${depots.id} != ${excludeDepotId}`,
    });

    const results: DepotWithCapacity[] = [];

    for (const depot of otherDepots) {
      const capacity = await this.getCapacity(depot.id, week);
      if (!capacity) continue;

      // Get PM hours for this depot/week
      const pmHours = await this.getPmHoursForPeriod(depot.id, week, addDays(week, 6));

      // Calculate available capacity
      const weeklyCapacity = this.calculateWeeklyCapacity(capacity);
      const availableHours = weeklyCapacity.regular + weeklyCapacity.overtime - pmHours;

      if (availableHours >= minHours) {
        results.push({
          depotId: depot.id,
          depotCode: depot.code,
          depotName: depot.name,
          availableHours: Math.min(availableHours, minHours),
        });
      }
    }

    // Sort by available hours (descending)
    return results.sort((a, b) => b.availableHours - a.availableHours);
  }

  /**
   * Get base labor rate for a depot
   */
  private async getBaseRate(depotId?: string): Promise<number> {
    if (!depotId) {
      return DEFAULT_BASE_RATE;
    }

    const rate = await this.db.query.laborRates.findFirst({
      where: and(
        eq(laborRates.depotId, depotId),
        lte(laborRates.effectiveFrom, format(new Date(), 'yyyy-MM-dd')),
        or(isNull(laborRates.effectiveTo), gte(laborRates.effectiveTo, format(new Date(), 'yyyy-MM-dd')))
      ),
      orderBy: [desc(laborRates.effectiveFrom)],
    });

    return rate ? parseFloat(rate.regularHourlyRate ?? String(DEFAULT_BASE_RATE)) : DEFAULT_BASE_RATE;
  }

  // ===========================================================================
  // Private: Apply Adjustments & Calculate Metrics
  // ===========================================================================

  /**
   * Apply adjustments to projections (simulation, not persisted)
   */
  private applyAdjustments(
    projections: ProjectionData[],
    adjustments: ProposedAdjustment[]
  ): ProjectionData[] {
    // Create deep copy
    const leveled = projections.map((p) => ({
      ...p,
      required: { ...p.required },
      available: { ...p.available },
    }));

    // Build lookup by week
    const weekMap = new Map(leveled.map((p) => [p.week.toISOString(), p]));

    for (const adj of adjustments) {
      if (adj.type === 'MANUAL_REVIEW') continue;

      const sourceKey = adj.sourcePeriod.start.toISOString();
      const source = weekMap.get(sourceKey);

      if (adj.type === 'ADVANCE_PM' || adj.type === 'DEFER_PM') {
        // Move hours from source to target
        if (source && adj.targetPeriod) {
          const targetKey = adj.targetPeriod.start.toISOString();
          const target = weekMap.get(targetKey);

          if (target) {
            source.required.pm -= adj.hoursAdjusted;
            source.required.total -= adj.hoursAdjusted;
            target.required.pm += adj.hoursAdjusted;
            target.required.total += adj.hoursAdjusted;
          }
        }
      } else if (adj.type === 'ADD_OVERTIME') {
        // Increase available hours in source
        if (source) {
          // Overtime is already counted in available.total
          // No change needed to projected available hours
        }
      } else if (adj.type === 'CROSS_DEPOT' || adj.type === 'ADD_CONTRACTOR') {
        // Reduce required hours in source (work transferred out)
        if (source) {
          source.required.total -= adj.hoursAdjusted;
        }
      }
    }

    // Recalculate metrics for all weeks
    for (const p of leveled) {
      p.variance = p.available.total - p.required.total;
      p.utilizationPct = p.available.total > 0 ? p.required.total / p.available.total : 0;
      p.isOverloaded = p.utilizationPct > MAX_UTILIZATION;
      p.isUnderutilized = p.utilizationPct < MIN_UTILIZATION;
    }

    return leveled;
  }

  /**
   * Calculate aggregate metrics
   */
  private calculateMetrics(projections: ProjectionData[]): LevelingMetrics {
    if (projections.length === 0) {
      return {
        avgUtilization: 0,
        minUtilization: 0,
        maxUtilization: 0,
        overloadedWeeks: 0,
        underutilizedWeeks: 0,
        totalRequiredHours: 0,
        totalAvailableHours: 0,
      };
    }

    const utilizations = projections.map((p) => p.utilizationPct);

    return {
      avgUtilization: utilizations.reduce((a, b) => a + b, 0) / utilizations.length,
      minUtilization: Math.min(...utilizations),
      maxUtilization: Math.max(...utilizations),
      overloadedWeeks: projections.filter((p) => p.isOverloaded).length,
      underutilizedWeeks: projections.filter((p) => p.isUnderutilized).length,
      totalRequiredHours: projections.reduce((sum, p) => sum + p.required.total, 0),
      totalAvailableHours: projections.reduce((sum, p) => sum + p.available.total, 0),
    };
  }

  /**
   * Group projections by depot
   */
  private groupByDepot(projections: ProjectionData[]): Map<string, ProjectionData[]> {
    const result = new Map<string, ProjectionData[]>();

    for (const p of projections) {
      const existing = result.get(p.depotId) ?? [];
      existing.push(p);
      result.set(p.depotId, existing);
    }

    return result;
  }

  // ===========================================================================
  // Private: Persistence
  // ===========================================================================

  /**
   * Persist projections and adjustments to database
   */
  private async persistProjections(
    runId: string,
    projections: ProjectionData[],
    adjustments: ProposedAdjustment[]
  ): Promise<void> {
    await this.inTransaction('persistProjections', async (tx, span) => {
      span.setAttribute('projectionRunId', runId);
      span.setAttribute('projectionCount', projections.length);
      span.setAttribute('adjustmentCount', adjustments.length);

      // Insert projections
      for (const p of projections) {
        const [inserted] = await tx
          .insert(manhourProjections)
          .values({
            projectionRunId: runId,
            depotId: p.depotId,
            periodStart: format(p.week, 'yyyy-MM-dd'),
            periodEnd: format(addDays(p.week, 6), 'yyyy-MM-dd'),
            granularity: p.granularity,
            requiredPmHours: String(p.required.pm),
            requiredCorrectiveHours: String(p.required.corrective),
            requiredOverhaulHours: String(p.required.overhaul),
            requiredTotalHours: String(p.required.total),
            availableRegularHours: String(p.available.regular),
            availableOvertimeHours: String(p.available.overtime),
            availableTotalHours: String(p.available.total),
          })
          .returning();

        // Insert adjustments for this projection
        const projectionAdjustments = adjustments.filter(
          (a) =>
            a.sourcePeriod.start.toISOString() === p.week.toISOString() &&
            (!p.depotCode || a.sourcePeriod.start.toISOString() === p.week.toISOString())
        );

        for (const adj of projectionAdjustments) {
          await tx.insert(manhourAdjustments).values({
            projectionId: inserted.id,
            adjustmentType: adj.type,
            sourcePeriodStart: format(adj.sourcePeriod.start, 'yyyy-MM-dd'),
            sourcePeriodEnd: format(adj.sourcePeriod.end, 'yyyy-MM-dd'),
            targetPeriodStart: adj.targetPeriod
              ? format(adj.targetPeriod.start, 'yyyy-MM-dd')
              : null,
            targetPeriodEnd: adj.targetPeriod ? format(adj.targetPeriod.end, 'yyyy-MM-dd') : null,
            hoursAdjusted: String(adj.hoursAdjusted),
            affectedPmIds: adj.affectedPMs,
            affectedTrainIds: adj.affectedTrains,
            costImpact: String(adj.costImpact),
            riskImpact: adj.riskLevel,
            reason: adj.reason,
            status: 'PROPOSED',
          });
        }
      }
    });
  }
}

